<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu-like Desktop Environment</title>
    <style>
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            user-select: none;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, "Open Sans", "Helvetica Neue", sans-serif;
            overflow: hidden;
            height: 100vh;
            width: 100vw;
        }

        /* Desktop */
        #desktop {
            position: relative;
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #2e3440 0%, #3b4252 100%);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: absolute;
            bottom: 0;
            left: 0;
            right: 0;
            height: 48px;
            background-color: rgba(31, 35, 42, 0.9);
            display: flex;
            align-items: center;
            padding: 0 16px;
            backdrop-filter: blur(10px);
            z-index: 1000;
        }

        .launcher {
            width: 48px;
            height: 48px;
            margin-right: 12px;
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: background-color 0.2s, transform 0.2s;
        }

        .launcher:hover {
            background-color: rgba(255, 255, 255, 0.1);
            transform: scale(1.05);
        }

        .launcher-icon {
            width: 32px;
            height: 32px;
            border-radius: 6px;
            background-color: #4c566a;
            display: flex;
            align-items: center;
            justify-content: center;
            color: white;
            font-size: 18px;
        }

        /* Windows */
        .window {
            position: absolute;
            width: 400px;
            height: 300px;
            background-color: #2d3540;
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            min-width: 360px;
            min-height: 240px;
        }

        .window-header {
            height: 32px;
            background-color: #3b4252;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 12px;
            cursor: default;
        }

        .window-title {
            color: white;
            font-size: 14px;
            font-weight: 500;
        }

        .window-controls {
            display: flex;
            gap: 8px;
        }

        .win-close {
            width: 12px;
            height: 12px;
            border-radius: 50%;
            background-color: #bf616a;
            cursor: pointer;
            transition: transform 0.2s;
        }

        .win-close:hover {
            transform: scale(1.1);
        }

        .window-content {
            flex: 1;
            overflow: auto;
            padding: 16px;
            color: #d8dee9;
        }

        /* Files App */
        #files-window {
            top: 20%;
            left: 30%;
            width: 500px;
            height: 400px;
        }

        .fs-path-bar {
            background-color: rgba(255, 255, 255, 0.1);
            padding: 8px 16px;
            border-radius: 4px;
            margin-bottom: 16px;
            font-family: monospace;
            color: #eceff4;
        }

        .fs-path-bar button {
            background-color: rgba(255, 255, 255, 0.2);
            border: none;
            border-radius: 4px;
            padding: 4px 8px;
            color: #eceff4;
            cursor: pointer;
            font-size: 14px;
        }

        .fs-path-bar button:hover {
            background-color: rgba(255, 255, 255, 0.3);
        }

        .fs-item {
            display: flex;
            align-items: center;
            padding: 8px 16px;
            border-radius: 4px;
            cursor: pointer;
            transition: background-color 0.2s;
            margin-bottom: 4px;
        }

        .fs-item:hover {
            background-color: rgba(255, 255, 255, 0.1);
        }

        .fs-item-icon {
            width: 24px;
            height: 24px;
            margin-right: 12px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 16px;
        }

        .folder-icon { color: #81a1c1; }
        .file-icon { color: #d8dee9; }

        /* Notepad App */
        #notepad-window {
            top: 20%;
            left: 50%;
            width: 600px;
            height: 450px;
        }

        .tabs-container {
            display: flex;
            background-color: #3b4252;
            border-bottom: 1px solid #4c566a;
        }

        .tab-strip {
            display: flex;
            overflow-x: auto;
            flex: 1;
        }

        .tab {
            padding: 8px 16px;
            background-color: rgba(255, 255, 255, 0.1);
            border-right: 1px solid #4c566a;
            cursor: pointer;
            font-size: 14px;
            white-space: nowrap;
            min-width: 80px;
        }

        .tab.active {
            background-color: #434c5e;
            color: #eceff4;
            border-bottom: 2px solid #81a1c1;
        }

        .tab:hover:not(.active) {
            background-color: rgba(255, 255, 255, 0.05);
        }

        .new-tab-btn {
            width: 32px;
            height: 32px;
            display: flex;
            align-items: center;
            justify-content: center;
            background-color: rgba(255, 255, 255, 0.1);
            border-left: 1px solid #4c566a;
            cursor: pointer;
            color: white;
        }

        .new-tab-btn:hover {
            background-color: rgba(255, 255, 255, 0.2);
        }

        #editor-container {
            flex: 1;
            position: relative;
        }

        #editor {
            width: 100%;
            height: 100%;
            background-color: #2d3540;
            color: #eceff4;
            border: none;
            padding: 16px;
            font-family: monospace;
            font-size: 14px;
            resize: none;
            outline: none;
        }

        /* Scrollbar styling */
        ::-webkit-scrollbar {
            width: 8px;
            height: 8px;
        }

        ::-webkit-scrollbar-track {
            background: rgba(255, 255, 255, 0.1);
        }

        ::-webkit-scrollbar-thumb {
            background: rgba(255, 255, 255, 0.3);
            border-radius: 4px;
        }

        ::-webkit-scrollbar-thumb:hover {
            background: rgba(255, 255, 255, 0.4);
        }

        /* Dragging */
        .dragging {
            cursor: move;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Taskbar -->
        <div id="taskbar">
            <div class="launcher" id="open-files">
                <div class="launcher-icon">📁</div>
            </div>
            <div class="launcher" id="open-notepad">
                <div class="launcher-icon">📝</div>
            </div>
        </div>

        <!-- Files Window -->
        <div id="files-window" class="window" style="display: none;">
            <div class="window-header">
                <span class="window-title">Files</span>
                <div class="window-controls">
                    <div class="win-close"></div>
                </div>
            </div>
            <div class="window-content">
                <div class="fs-path-bar" id="files-path">/</div>
                <button id="files-up" style="margin-bottom: 16px; cursor: pointer;">⬆ Up</button>
                <div id="files-list"></div>
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window" style="display: none;">
            <div class="window-header">
                <span class="window-title">Notepad</span>
                <div class="window-controls">
                    <div class="win-close"></div>
                </div>
            </div>
            <div class="tabs-container">
                <div class="tab-strip" id="tabs">
                    <!-- Tabs will be added here -->
                </div>
                <div class="new-tab-btn" id="new-tab">+</div>
            </div>
            <div id="editor-container">
                <textarea id="editor"></textarea>
            </div>
        </div>
    </div>

    <script>
        // File system data structure
        const fileSystem = {
            "/": ["bin", "etc", "home", "usr", "var"],
            "/bin": ["bash", "ls", "cat", "cp", "mv"],
            "/etc": ["config", "hosts", "passwd"],
            "/home": ["user"],
            "/home/user": ["Documents", "Downloads", "Pictures", "notes.txt"],
            "/home/user/Documents": ["report.docx", "resume.pdf"],
            "/home/user/Downloads": ["software.iso", "update.zip"],
            "/home/user/Pictures": ["wallpaper.png", "screenshot.jpg"],
            "/usr": ["bin", "lib", "share"],
            "/var": ["log", "cache", "tmp"]
        };

        // Files app state
        let currentPath = "/";

        // Notepad state
        let tabs = [];
        let activeTabId = null;
        let tabCounter = 0;

        // DOM Elements
        const desktop = document.getElementById('desktop');
        const taskbar = document.getElementById('taskbar');
        const openFilesBtn = document.getElementById('open-files');
        const openNotepadBtn = document.getElementById('open-notepad');
        const filesWindow = document.getElementById('files-window');
        const notepadWindow = document.getElementById('notepad-window');

        // Files app elements
        const filesPathDisplay = document.getElementById('files-path');
        const filesList = document.getElementById('files-list');
        const filesUpBtn = document.getElementById('files-up');

        // Notepad elements
        const tabsContainer = document.getElementById('tabs');
        const newTabBtn = document.getElementById('new-tab');
        const editor = document.getElementById('editor');

        // Files app functions
        function updateFilesPath() {
            filesPathDisplay.textContent = currentPath;

            // Update up button visibility
            if (currentPath === "/") {
                filesUpBtn.style.visibility = "hidden";
            } else {
                filesUpBtn.style.visibility = "visible";
            }
        }

        function renderFileList() {
            filesList.innerHTML = '';

            const items = fileSystem[currentPath] || [];

            // First show folders, then files
            const folders = items.filter(item => fileSystem.hasOwnProperty(`/${item}`) || item === 'home' || item === 'user');
            const files = items.filter(item => !fileSystem.hasOwnProperty(`/${item}` && item !== 'home' && item !== 'user'));

            // Show parent directory if not at root
            if (currentPath !== "/") {
                const parentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';
                const upItem = document.createElement('div');
                upItem.className = 'fs-item';
                upItem.innerHTML = '<span class="fs-item-icon folder-icon">⬆</span><span>.. (Parent Directory)</span>';
                upItem.addEventListener('click', function() {
                    if (currentPath !== "/") {
                        currentPath = parentPath;
                        updateFilesPath();
                        renderFileList();
                    }
                });
                filesList.appendChild(upItem);
            }

            // Render folders
            folders.forEach(item => {
                const itemDiv = document.createElement('div');
                itemDiv.className = 'fs-item';
                itemDiv.innerHTML = `<span class="fs-item-icon folder-icon">📁</span><span>${item}</span>`;
                itemDiv.addEventListener('dblclick', function() {
                    currentPath = `${currentPath}/${item}`;
                    updateFilesPath();
                    renderFileList();
                });
                filesList.appendChild(itemDiv);
            });

            // Render files
            files.forEach(item => {
                const itemDiv = document.createElement('div');
                itemDiv.className = 'fs-item';
                itemDiv.innerHTML = `<span class="fs-item-icon file-icon">📄</span><span>${item}</span>`;
                itemDiv.addEventListener('dblclick', function() {
                    alert(`Opening ${item}... (This is a demo - double-click to open files in real app)`);
                });
                filesList.appendChild(itemDiv);
            });
        }

        // Notepad functions
        function saveTabsToStorage() {
            const tabsData = tabs.map(tab => ({
                id: tab.id,
                title: tab.title,
                content: tab.content
            }));
            localStorage.setItem('ubuntu_notepad_tabs', JSON.stringify(tabsData));
            if (activeTabId !== null) {
                localStorage.setItem('ubuntu_notepad_active_tab', activeTabId.toString());
            }
        }

        function loadTabsFromStorage() {
            const savedTabs = localStorage.getItem('ubuntu_notepad_tabs');
            const savedActiveTab = localStorage.getItem('ubuntu_notepad_active_tab');

            if (savedTabs) {
                tabs = JSON.parse(savedTabs);

                // Create tab elements for each saved tab
                tabs.forEach(tab => {
                    createTabElement(tab.id, tab.title, false);
                });

                if (tabs.length > 0) {
                    activeTabId = parseInt(savedActiveTab) || tabs[0].id;
                    updateEditor();
                    highlightActiveTab();
                }
            } else {
                // Create initial empty tab
                createNewTab();
            }
        }

        function createNewTab() {
            const id = ++tabCounter;
            const title = `Tab ${tabs.length + 1}`;

            tabs.push({
                id: id,
                title: title,
                content: ''
            });

            activeTabId = id;
            createTabElement(id, title, true);
            updateEditor();
            saveTabsToStorage();
        }

        function createTabElement(id, title, isActive) {
            const tab = document.createElement('div');
            tab.className = `tab ${isActive ? 'active' : ''}`;
            tab.textContent = title;
            tab.dataset.id = id;

            // Click to switch tabs
            tab.addEventListener('click', function() {
                activeTabId = id;
                updateEditor();
                highlightActiveTab();
            });

            tabsContainer.appendChild(tab);
        }

        function highlightActiveTab() {
            const allTabs = document.querySelectorAll('.tab');
            allTabs.forEach(t => t.classList.remove('active'));

            if (activeTabId !== null) {
                const activeTab = document.querySelector(`.tab[data-id="${activeTabId}"]`);
                if (activeTab) {
                    activeTab.classList.add('active');
                }
            }
        }

        function updateEditor() {
            if (activeTabId === null) return;

            const tab = tabs.find(t => t.id === activeTabId);
            if (tab) {
                editor.value = tab.content;
            }
        }

        // Event Listeners
        // Files app
        filesUpBtn.addEventListener('click', function() {
            if (currentPath !== "/") {
                currentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';
                updateFilesPath();
                renderFileList();
            }
        });

        // Notepad app
        newTabBtn.addEventListener('click', createNewTab);

        editor.addEventListener('input', function() {
            if (activeTabId !== null) {
                const tab = tabs.find(t => t.id === activeTabId);
                if (tab) {
                    tab.content = editor.value;
                    saveTabsToStorage();
                }
            }
        });

        // Window management
        openFilesBtn.addEventListener('click', function() {
            filesWindow.style.display = 'flex';

            // Initialize files app if not already done
            updateFilesPath();
            renderFileList();
        });

        openNotepadBtn.addEventListener('click', function() {
            notepadWindow.style.display = 'flex';

            // Load tabs from storage or create new tab
            loadTabsFromStorage();
        });

        // Close buttons
        filesWindow.querySelector('.win-close').addEventListener('click', function() {
            filesWindow.style.display = 'none';
        });

        notepadWindow.querySelector('.win-close').addEventListener('click', function() {
            notepadWindow.style.display = 'none';
        });

        // Window dragging functionality
        let isDragging = false;
        let dragOffsetX = 0;
        let dragOffsetY = 0;
        let draggedElement = null;

        document.addEventListener('mousedown', function(e) {
            const header = e.target.closest('.window-header');
            if (header) {
                isDragging = true;
                draggedElement = header.parentElement;

                // Get the position of the window
                const rect = draggedElement.getBoundingClientRect();
                dragOffsetX = e.clientX - rect.left;
                dragOffsetY = e.clientY - rect.top;

                draggedElement.classList.add('dragging');
            }
        });

        document.addEventListener('mousemove', function(e) {
            if (isDragging && draggedElement) {
                // Calculate new position
                let newX = e.clientX - dragOffsetX;
                let newY = e.clientY - dragOffsetY;

                // Keep within viewport bounds
                const desktopRect = desktop.getBoundingClientRect();
                const winRect = draggedElement.getBoundingClientRect();

                // Clamp X position
                if (newX < 0) newX = 0;
                if (newX + winRect.width > desktopRect.width) newX = desktopRect.width - winRect.width;

                // Clamp Y position (taskbar is at bottom)
                const taskbarHeight = 48; // Height of the taskbar
                if (newY < 0) newY = 0;
                if (newY + winRect.height > desktopRect.height - taskbarHeight) newY = desktopRect.height - taskbarHeight - winRect.height;

                draggedElement.style.left = `${newX}px`;
                draggedElement.style.top = `${newY}px`;
            }
        });

        document.addEventListener('mouseup', function() {
            isDragging = false;
            if (draggedElement) {
                draggedElement.classList.remove('dragging');
                draggedElement = null;
            }
        });

        // Initialize files app on first load
        updateFilesPath();
        renderFileList();

        // Create initial empty tab for notepad if no saved tabs
        loadTabsFromStorage();
    </script>
</body>
</html>
